/* global React, ReactDOM, Chart */
// Static React (CDN) UI – no build step.
// Data is loaded from site/data/* generated by scripts/generate_site.py.

const BUDGET = 100.0;
const MAX_PER_CLUB = 3;
const POS_CAP = { GK: 2, DEF: 5, MID: 5, FWD: 3 };

const DEFAULT_ENTRY_ID = 1093603;
const DEFAULT_GW = 20;

function toNum(v, fallback = 0) {
  const n = typeof v === 'number' ? v : parseFloat(String(v));
  return Number.isFinite(n) ? n : fallback;
}

function toInt(v, fallback = 0) {
  const n = typeof v === 'number' ? v : parseInt(String(v), 10);
  return Number.isFinite(n) ? n : fallback;
}

function clamp(n, lo, hi) {
  return Math.max(lo, Math.min(hi, n));
}

function safeText(s) {
  return (s ?? '').toString();
}

function roundToHalf(n) {
  return Math.round(toNum(n, 0) * 2) / 2;
}

function formatMaybeNum(v, digits = 1) {
  if (v == null || v === '') return '—';
  const n = toNum(v, NaN);
  if (!Number.isFinite(n)) return safeText(v);
  return n.toFixed(digits);
}

function badgeUrl(teamShort) {
  const t = safeText(teamShort).trim();
  if (!t) return 'assets/badges/unknown.svg';
  return `assets/badges/${encodeURIComponent(t)}.svg`;
}

function fdrPill(fdr, label) {
  const f = clamp(toInt(fdr, 3), 1, 5);
  const text = label ? `${f} ${label}` : `${f}`;
  return React.createElement('span', { className: `fdr fdr-${f}` }, text);
}

async function fetchFirstJson(urls) {
  for (const url of urls) {
    try {
      const r = await fetch(url, { cache: 'no-store' });
      if (!r.ok) continue;
      return await r.json();
    } catch (_) {
      // continue
    }
  }
  return null;
}

async function fetchFirstText(urls) {
  for (const url of urls) {
    try {
      const r = await fetch(url, { cache: 'no-store' });
      if (!r.ok) continue;
      return await r.text();
    } catch (_) {
      // continue
    }
  }
  return '';
}

function parseCsv(text) {
  const src = safeText(text).trim();
  if (!src) return [];
  const lines = src.split(/\r?\n/).filter(Boolean);
  if (!lines.length) return [];

  function splitCsvLine(line) {
    const out = [];
    let cur = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') {
        if (inQuotes && line[i + 1] === '"') {
          cur += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (ch === ',' && !inQuotes) {
        out.push(cur);
        cur = '';
      } else {
        cur += ch;
      }
    }
    out.push(cur);
    return out.map((s) => s.trim());
  }

  const header = splitCsvLine(lines[0]);
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const cols = splitCsvLine(lines[i]);
    const obj = {};
    for (let j = 0; j < header.length; j++) obj[header[j]] = cols[j] ?? '';
    rows.push(obj);
  }
  return rows;
}

function normalizeProjections(rows) {
  const POS_MAP = { 1: 'GK', 2: 'DEF', 3: 'MID', 4: 'FWD' };
  return (rows || []).map((r) => {
    const out = { ...r };

    out.player_id = toInt(out.player_id ?? out.element ?? out.id, 0);
    out.web_name = safeText(out.web_name ?? out.name ?? out.player).trim();

    const rawPos = out.position ?? out.pos;
    const posNum = toInt(rawPos, NaN);
    out.position = Number.isFinite(posNum) ? (POS_MAP[posNum] || safeText(rawPos)) : safeText(rawPos);

    out.team = safeText(out.team ?? out.short_name ?? out.club).trim();
    out.team_id = toInt(out.team_id ?? out.teamid, 0);

    const priceRaw = out.price ?? out.now_cost ?? out.value;
    let price = toNum(priceRaw, 0);
    if (price > 1000) price = price / 10.0;
    out.price = price;

    out.proj_points = toNum(out.proj_points ?? out.projected_points ?? out.proj ?? out.predicted_points, 0);

    // optional extras
    out.fixture_difficulty = toInt(out.fixture_difficulty ?? out.fdr ?? out.difficulty, 3);

    return out;
  });
}

function buildFixtureIndex(fixturesRaw) {
  // Expects FPL fixture shape: [{ event, team_h, team_a, team_h_difficulty, team_a_difficulty, ... }, ...]
  const idx = {};
  const rows = Array.isArray(fixturesRaw)
    ? fixturesRaw
    : fixturesRaw && Array.isArray(fixturesRaw.fixtures)
      ? fixturesRaw.fixtures
      : [];

  for (const fx of rows) {
    const gw = toInt(fx.event, 0);
    const th = toInt(fx.team_h, 0);
    const ta = toInt(fx.team_a, 0);
    if (!gw || !th || !ta) continue;

    const h = { opp_id: ta, ha: 'H', fdr: toInt(fx.team_h_difficulty, 3) };
    const a = { opp_id: th, ha: 'A', fdr: toInt(fx.team_a_difficulty, 3) };

    idx[th] = idx[th] || {};
    idx[th][gw] = idx[th][gw] || [];
    idx[th][gw].push(h);

    idx[ta] = idx[ta] || {};
    idx[ta][gw] = idx[ta][gw] || [];
    idx[ta][gw].push(a);
  }

  return idx;
}

function summarizeTeam(team) {
  const rows = team || [];
  const cost = rows.reduce((s, p) => s + toNum(p.price, 0), 0);
  const points = rows.reduce((s, p) => s + toNum(p.proj_points, 0), 0);
  const counts = { GK: 0, DEF: 0, MID: 0, FWD: 0 };
  const byClub = {};
  for (const p of rows) {
    const pos = safeText(p.position);
    if (counts[pos] != null) counts[pos] += 1;
    const club = safeText(p.team);
    if (club) byClub[club] = (byClub[club] || 0) + 1;
  }
  return { cost, points, counts, byClub, size: rows.length };
}

function canAddPlayer(team, player) {
  const t = team || [];
  const p = player || {};
  const summary = summarizeTeam(t);

  if (summary.size >= 15) return [false, 'Squad already has 15 players'];
  if (t.some((x) => toInt(x.player_id, 0) && toInt(x.player_id, 0) === toInt(p.player_id, 0))) return [false, 'Already in squad'];

  const pos = safeText(p.position);
  if (POS_CAP[pos] != null && summary.counts[pos] >= POS_CAP[pos]) return [false, `Max ${pos} reached`];

  const club = safeText(p.team);
  if (club && (summary.byClub[club] || 0) >= MAX_PER_CLUB) return [false, 'Max 3 per club'];

  const newCost = summary.cost + toNum(p.price, 0);
  if (newCost > BUDGET + 1e-9) return [false, 'Over £100.0m budget'];

  return [true, ''];
}

function Tabs({ active, setActive }) {
  const tabs = [
    ['team', 'My Team'],
    ['proj', 'Projected Points'],
    ['ticker', 'Fixture Difficulty'],
    ['stats', 'Key Stats'],
    ['profile', 'Player Profile'],
    ['planner', 'Transfer Planner'],
  ];
  return React.createElement(
    'div',
    { className: 'nav nav-tabs' },
    tabs.map(([k, label]) =>
      React.createElement(
        'button',
        {
          key: k,
          className: `nav-link ${active === k ? 'active' : ''}`,
          type: 'button',
          onClick: () => setActive(k),
        },
        label
      )
    )
  );
}

function LoadingCard({ text }) {
  return React.createElement('div', { className: 'card p-3' }, text || 'Loading…');
}

