function FixtureTickerTab({ projections, fixtureIndex, teamsById }) {
  const [gwStart, setGwStart] = React.useState(21);
  const [gwEnd, setGwEnd] = React.useState(26);

  const teams = React.useMemo(() => {
    const uniq = new Map();
    for (const p of projections || []) {
      const tid = toInt(p.team_id, 0);
      const tname = safeText(p.team).trim();
      if (!tid && !tname) continue;
      const key = tid || tname;
      if (!uniq.has(key)) uniq.set(key, { team_id: tid, team: tname });
    }
    return Array.from(uniq.values()).sort((a, b) => safeText(a.team).localeCompare(safeText(b.team)));
  }, [projections]);

  function teamNameFromId(tid) {
    const t = teamsById && tid ? teamsById[tid] : null;
    return t ? (t.short_name || t.team_name || String(tid)) : String(tid);
  }

  if (!fixtureIndex || !Object.keys(fixtureIndex).length) {
    return React.createElement('div', { className: 'card p-3' },
      React.createElement('div', { className: 'text-muted' }, 'No fixtures staged yet. Add data/fixtures.json and run scripts/generate_site.py to stage site/data/fixtures.json.')
    );
  }

  const gws = [];
  for (let gw = toInt(gwStart, 21); gw <= toInt(gwEnd, 26); gw++) gws.push(gw);

  return React.createElement(
    'div',
    null,
    React.createElement('div', { className: 'card p-3 mb-3' },
      React.createElement('div', { className: 'row g-2 align-items-end' },
        React.createElement('div', { className: 'col-sm-3' },
          React.createElement('label', { className: 'form-label' }, 'GW Start'),
          React.createElement('input', { className: 'form-control', value: String(gwStart), onChange: (e) => setGwStart(toInt(e.target.value, 21)) })
        ),
        React.createElement('div', { className: 'col-sm-3' },
          React.createElement('label', { className: 'form-label' }, 'GW End'),
          React.createElement('input', { className: 'form-control', value: String(gwEnd), onChange: (e) => setGwEnd(toInt(e.target.value, 26)) })
        )
      )
    ),

    React.createElement('div', { className: 'card p-0 overflow-hidden' },
      React.createElement('div', { className: 'table-responsive' },
        React.createElement('table', { className: 'table table-sm mb-0' },
          React.createElement('thead', null,
            React.createElement('tr', null,
              React.createElement('th', null, 'Team'),
              ...gws.map((gw) => React.createElement('th', { key: gw, className: 'text-center' }, `GW${gw}`))
            )
          ),
          React.createElement('tbody', null,
            teams.map((t) => {
              const tid = toInt(t.team_id, 0);
              const label = tid ? teamNameFromId(tid) : safeText(t.team);
              return React.createElement('tr', { key: tid || label },
                React.createElement('td', null, label),
                ...gws.map((gw) => {
                  const fxList = tid ? (fixtureIndex[tid] && fixtureIndex[tid][gw]) : [];
                  if (!fxList || !fxList.length) return React.createElement('td', { key: gw, className: 'text-center text-muted' }, '—');
                  const top = fxList[0];
                  return React.createElement('td', { key: gw, className: 'text-center' }, fdrPill(top.fdr, top.ha));
                })
              );
            })
          )
        )
      )
    )
  );
}

