function TransferPlannerTab({ projections }) {
  const [team, setTeam] = React.useState([]);
  const [pos, setPos] = React.useState('ALL');
  const [teamFilter, setTeamFilter] = React.useState('ALL');
  const [maxCost, setMaxCost] = React.useState(12.0);
  const [query, setQuery] = React.useState('');
  const [userId, setUserId] = React.useState('demo');
  const [apiBase, setApiBase] = React.useState('http://127.0.0.1:8080');
  const [message, setMessage] = React.useState('');

  const projectionsById = React.useMemo(() => {
    const m = {};
    for (const p of projections || []) {
      const pid = toInt(p.player_id, 0);
      if (pid) m[pid] = p;
    }
    return m;
  }, [projections]);

  const summary = summarizeTeam(team);

  const teams = React.useMemo(() => {
    const set = new Set((projections || []).map((p) => safeText(p.team)).filter(Boolean));
    return ['ALL', ...Array.from(set).sort()];
  }, [projections]);

  const priceOptions = React.useMemo(() => {
    const out = [];
    for (let p = 0; p <= 20.0001; p += 0.5) out.push(roundToHalf(p));
    return out;
  }, []);

  const filtered = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return (projections || [])
      .filter((p) => pos === 'ALL' || safeText(p.position) === pos)
      .filter((p) => teamFilter === 'ALL' || safeText(p.team) === teamFilter)
      .filter((p) => toNum(p.price, 0) <= toNum(maxCost, 99))
      .filter((p) => !q || safeText(p.web_name).toLowerCase().includes(q) || safeText(p.team).toLowerCase().includes(q))
      .sort((a, b) => toNum(b.proj_points, 0) - toNum(a.proj_points, 0));
  }, [projections, pos, teamFilter, maxCost, query]);

  function add(p) {
    const [ok] = canAddPlayer(team, p);
    if (!ok) return;
    setTeam([...(team || []), p]);
  }

  function remove(pid) {
    setTeam((team || []).filter((x) => toInt(x.player_id, 0) !== toInt(pid, 0)));
  }

  function slotHeader(label) {
    return React.createElement('div', { className: 'w-100 fw-semibold mt-2' }, label);
  }

  function slotCards(posKey, n) {
    const list = (team || []).filter((p) => safeText(p.position) === posKey);
    const out = [];
    for (let i = 0; i < n; i++) {
      const p = list[i];
      out.push(
        React.createElement('div', { key: `${posKey}-${i}`, className: 'card p-2' },
          p
            ? React.createElement('div', { className: 'd-flex justify-content-between align-items-center' },
                React.createElement('div', null,
                  React.createElement('div', { className: 'fw-semibold' }, safeText(p.web_name)),
                  React.createElement('div', { className: 'small text-muted' }, `${safeText(p.team)} · £${toNum(p.price, 0).toFixed(1)}m`)
                ),
                React.createElement('button', { className: 'btn btn-sm btn-outline-danger', onClick: () => remove(p.player_id) }, 'Remove')
              )
            : React.createElement('div', { className: 'text-muted' }, 'Empty slot')
        )
      );
    }
    return out;
  }

  return React.createElement(
    'div',
    null,
    React.createElement('div', { className: 'row g-3' },
      React.createElement('div', { className: 'col-lg-8' },
        React.createElement('h5', null, 'Squad Canvas'),
        React.createElement('div', { className: 'formation-grid mb-3' },
          slotHeader('GK'),
          ...slotCards('GK', POS_CAP.GK),
          slotHeader('DEF'),
          ...slotCards('DEF', POS_CAP.DEF),
          slotHeader('MID'),
          ...slotCards('MID', POS_CAP.MID),
          slotHeader('FWD'),
          ...slotCards('FWD', POS_CAP.FWD)
        )
      ),
      React.createElement('div', { className: 'col-lg-4' },
        React.createElement('div', { className: 'card p-3 mb-3' },
          React.createElement('div', { className: 'd-flex justify-content-between align-items-center' },
            React.createElement('span', { className: 'fw-semibold' }, 'Saved Teams'),
            React.createElement('span', { className: 'text-muted small' }, 'Optional')
          ),
          React.createElement('label', { className: 'form-label mt-2' }, 'API Base'),
          React.createElement('input', { className: 'form-control mb-2', value: apiBase, onChange: (e) => setApiBase(e.target.value) }),
          React.createElement('label', { className: 'form-label' }, 'User ID'),
          React.createElement('input', { className: 'form-control mb-2', value: userId, onChange: (e) => setUserId(e.target.value) }),
          React.createElement('div', { className: 'd-flex gap-2' },
            React.createElement('button', {
              className: 'btn btn-sm btn-outline-primary',
              onClick: async () => {
                setMessage('');
                const uid = safeText(userId).trim();
                if (!uid) {
                  setMessage('Enter a user id first.');
                  return;
                }
                try {
                  const url = `${safeText(apiBase).replace(/\/$/, '')}/team/${encodeURIComponent(uid)}`;
                  const saved = await (await fetch(url, { cache: 'no-store' })).json();
                  const ids = Array.isArray(saved) ? saved : [];
                  const loaded = ids.map((x) => projectionsById[toInt(x, 0)]).filter(Boolean);
                  setTeam(loaded);
                  setMessage(loaded.length ? `Loaded ${loaded.length} players.` : 'Loaded empty team.');
                } catch (_) {
                  setMessage('Failed to load. Is site_api running on this API base?');
                }
              },
            }, 'Load'),
            React.createElement('button', {
              className: 'btn btn-sm btn-primary',
              onClick: async () => {
                setMessage('');
                const uid = safeText(userId).trim();
                if (!uid) {
                  setMessage('Enter a user id first.');
                  return;
                }
                try {
                  const url = `${safeText(apiBase).replace(/\/$/, '')}/team`;
                  const payload = { user_id: uid, team: (team || []).map((p) => toInt(p.player_id, 0)).filter(Boolean) };
                  await fetch(url, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload),
                  });
                  setMessage('Saved.');
                } catch (_) {
                  setMessage('Failed to save. Is site_api running and CORS enabled?');
                }
              },
            }, 'Save')
          ),
          message ? React.createElement('div', { className: 'alert alert-warning mt-2 mb-0 py-2' }, message) : null
        ),

        React.createElement('div', { className: 'card p-3 mb-3' },
          React.createElement('div', { className: 'd-flex justify-content-between' },
            React.createElement('span', null, 'Total Cost'),
            React.createElement('span', { className: 'badge text-bg-secondary' }, `£${summary.cost.toFixed(1)}m`)
          ),
          React.createElement('div', { className: 'd-flex justify-content-between mt-2' },
            React.createElement('span', null, 'Projected Points'),
            React.createElement('span', { className: 'badge text-bg-secondary' }, summary.points.toFixed(1))
          ),
          React.createElement('div', { className: 'text-muted small mt-2' }, 'Rules: £100.0m · max 3 per club · 15 total · 2 GK / 5 DEF / 5 MID / 3 FWD')
        ),

        React.createElement('div', { className: 'card p-3 mb-3' },
          React.createElement('label', { className: 'form-label' }, 'Position'),
          React.createElement('select', { className: 'form-select mb-2', value: pos, onChange: (e) => setPos(e.target.value) },
            ['ALL', 'GK', 'DEF', 'MID', 'FWD'].map((x) => React.createElement('option', { key: x, value: x }, x))
          ),
          React.createElement('label', { className: 'form-label' }, 'Team'),
          React.createElement('select', { className: 'form-select mb-2', value: teamFilter, onChange: (e) => setTeamFilter(e.target.value) },
            teams.map((t) => React.createElement('option', { key: t, value: t }, t))
          ),
          React.createElement('label', { className: 'form-label' }, 'Max Cost (£m)'),
          React.createElement('select', { className: 'form-select mb-2', value: maxCost, onChange: (e) => setMaxCost(toNum(e.target.value, 12)) },
            priceOptions.map((x) => React.createElement('option', { key: x, value: x }, x.toFixed(1)))
          ),
          React.createElement('label', { className: 'form-label' }, 'Search'),
          React.createElement('input', { className: 'form-control', placeholder: 'Name or team…', value: query, onChange: (e) => setQuery(e.target.value) })
        ),

        React.createElement('div', { className: 'card p-2' },
          React.createElement('div', { className: 'list-group' },
            filtered.slice(0, 40).map((p) => {
              const [ok, reason] = canAddPlayer(team, p);
              return React.createElement('div', { key: p.player_id || `${p.web_name}-${p.team}`, className: 'list-group-item d-flex justify-content-between align-items-center' },
                React.createElement('div', null,
                  React.createElement('div', { className: 'fw-semibold' }, safeText(p.web_name)),
                  React.createElement('div', { className: 'small text-muted' }, `${safeText(p.team)} · ${safeText(p.position)} · £${toNum(p.price, 0).toFixed(1)}`)
                ),
                React.createElement('button', { className: 'btn btn-sm btn-primary', disabled: !ok, title: reason, onClick: () => add(p) }, 'Add')
              );
            })
          )
        )
      )
    )
  );
}

function App() {
  const [activeTab, setActiveTab] = React.useState('team');
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState('');

  const [projections, setProjections] = React.useState([]);
  const [fixturesRaw, setFixturesRaw] = React.useState(null);
  const [statsRows, setStatsRows] = React.useState([]);
  const [teamsLookup, setTeamsLookup] = React.useState({});

  const [entryId, setEntryId] = React.useState(String(DEFAULT_ENTRY_ID));
  const [gw, setGw] = React.useState(String(DEFAULT_GW));
  const [myTeam, setMyTeam] = React.useState([]);

  const [selectedPlayer, setSelectedPlayer] = React.useState(null);

  const projectionsById = React.useMemo(() => {
    const m = {};
    for (const p of projections || []) {
      const pid = toInt(p.player_id, 0);
      if (pid) m[pid] = p;
    }
    return m;
  }, [projections]);

  const teamsById = React.useMemo(() => {
    const m = {};
    const list = (teamsLookup && Array.isArray(teamsLookup.teams)) ? teamsLookup.teams : [];
    for (const t of list) {
      const tid = toInt(t.id, 0);
      if (!tid) continue;
      m[tid] = {
        short_name: safeText(t.short_name || tid),
        team_name: safeText(t.team_name || t.name || t.short_name || tid),
      };
    }
    return m;
  }, [teamsLookup]);

  const fixtureIndex = React.useMemo(() => buildFixtureIndex(fixturesRaw), [fixturesRaw]);

  async function loadData() {
    setLoading(true);
    setError('');

    try {
      const proj = await fetchFirstJson([
        'data/projections.json',
        'projections.json',
        '../outputs/projections.json',
      ]);
      const rows = Array.isArray(proj) ? proj : [];
      const normalized = normalizeProjections(rows);
      setProjections(normalized);
      if (!selectedPlayer && normalized.length) setSelectedPlayer(normalized[0]);
    } catch (e) {
      setProjections([]);
      setError('Failed to load projections. Run scripts/generate_site.py first.');
    }

    try {
      const fx = await fetchFirstJson([
        'data/fixtures.json',
        'fixtures.json',
      ]);
      setFixturesRaw(fx);
    } catch (_) {
      setFixturesRaw(null);
    }

    try {
      const txt = await fetchFirstText([
        'data/stats.csv',
        'stats.csv',
      ]);
      setStatsRows(parseCsv(txt));
    } catch (_) {
      setStatsRows([]);
    }

    try {
      const teams = await fetchFirstJson([
        'data/teams.json',
        'teams.json',
      ]);
      setTeamsLookup(teams || {});
    } catch (_) {
      setTeamsLookup({});
    }

    setLoading(false);
  }

  async function reloadMyTeam() {
    const eid = toInt(entryId, DEFAULT_ENTRY_ID);
    const gwNum = toInt(gw, DEFAULT_GW);
    const url = `https://fantasy.premierleague.com/api/entry/${eid}/event/${gwNum}/picks/`;

    try {
      const js = await (await fetch(url, { cache: 'no-store' })).json();
      const picks = js.picks || [];
      const team = picks
        .map((pk) => projectionsById[toInt(pk.element, 0)])
        .filter(Boolean);
      setMyTeam(team);
      return;
    } catch (_) {
      // fallback
    }

    const local = await fetchFirstJson([
      'data/my_team.json',
      'my_team.json',
    ]);
    try {
      const picks = local && Array.isArray(local.picks) ? local.picks : Array.isArray(local) ? local : [];
      const team = (picks || [])
        .map((pk) => projectionsById[toInt(pk.element ?? pk.player_id ?? pk, 0)])
        .filter(Boolean);
      setMyTeam(team);
    } catch (_) {
      setMyTeam([]);
    }
  }

  React.useEffect(() => {
    loadData();
  }, []);

  React.useEffect(() => {
    if (!loading) reloadMyTeam();
  }, [loading]);

  function onSelectPlayer(p) {
    setSelectedPlayer(p);
    setActiveTab('profile');
  }

  if (loading) return React.createElement(LoadingCard, { text: 'Loading projections / fixtures / stats…' });

  return React.createElement(
    'div',
    null,
    React.createElement('h1', { className: 'mb-1' }, 'FPL Projections'),
    React.createElement('p', { className: 'text-muted' }, 'Explore projections, fixture difficulty, player profiles, and build a squad.'),
    error ? React.createElement('div', { className: 'alert alert-warning' }, error) : null,
    React.createElement(Tabs, { active: activeTab, setActive: setActiveTab }),
    React.createElement('div', { className: 'pt-3' },
      activeTab === 'team'
        ? React.createElement(MyTeamTab, { projectionsById, myTeam, entryId, setEntryId, gw, setGw, reloadMyTeam })
        : null,
      activeTab === 'proj'
        ? React.createElement(ProjectionsTab, { projections, onSelectPlayer })
        : null,
      activeTab === 'ticker'
        ? React.createElement(FixtureTickerTab, { projections, fixtureIndex, teamsById })
        : null,
      activeTab === 'stats'
        ? React.createElement(StatsTab, { statsRows })
        : null,
      activeTab === 'profile'
        ? React.createElement(PlayerProfileTab, { selectedPlayer })
        : null,
      activeTab === 'planner'
        ? React.createElement(TransferPlannerTab, { projections })
        : null
    )
  );
}

document.addEventListener('DOMContentLoaded', () => {
  const root = document.getElementById('root');
  if (!root) return;
  ReactDOM.createRoot(root).render(React.createElement(App));
});
